var userLogInDB = async (payload) => {
  const user = await prisma.user.findUnique({
    where: {
      email: payload.email
    }
  });
  if (!user) {
    throw new AppError_default(404, "User not exist");
  }
  const isPasswordMatched = await bcrypt2.compare(
    payload.password,
    user.password
  );
  if (!isPasswordMatched) {
    throw new AppError_default(401, "Invalid credentials");
  }
  const { password, ...userWithoutPassword } = user;
  const accessToken = jtwUtils.createToken(
    userWithoutPassword,
    envConfiq_default.jwt_access_secret,
    { expiresIn: envConfiq_default.jwt_access_expires_in }
  );
  return { accessToken, userWithoutPassword };
};
var registerUserDB = async (payload) => {
  const allowedFields = ["name", "email", "phone_no", "password", "role"];
  const extraFields = Object.keys(payload).filter(
    (key) => !allowedFields.includes(key)
  );
  if (extraFields.length > 0) {
    throw new AppError_default(400, `Unknown field(s): ${extraFields.join(", ")}`);
  }
  const { name, email, phone_no, password, role } = payload;
  const allowedRoles = ["customer", "technician"];
  if (role && !allowedRoles.includes(role)) {
    throw new AppError_default(400, "Invalid role. Allowed: customer, technician");
  }
  const userRole = role ?? "customer";
  const hashedPassword = await bcrypt2.hash(
    password,
    Number(envConfiq_default.bcrypt_salt_rounds)
  );
  const result = await prisma.$transaction(async (tx) => {
    const user = await tx.user.create({
      data: {
        name,
        email,
        phone_no,
        password: hashedPassword,
        role: userRole
      }
    });
    if (userRole === "technician") {
      const profile = await tx.technicianProfile.create({
        data: { user_id: user.id }
      });
      await tx.availability.createMany({
        data: defaultAvailability.map((slot) => ({
          technician_id: profile.id,
          ...slot
        }))
      });
    }
    return user;
  });
  const { password: _password, ...userWithoutPassword } = result;
  return userWithoutPassword;
};
